            JsonWorkspace workspace, scoped in TContext context, scoped in Corvus.Cql2Benchmark.Current.Cql2Schema.IsNullPredicate.Builder.Build<TContext> value, int initialCapacity = 30)
            #if NET9_0_OR_GREATER
            where TContext : allows ref struct
            #endif
        {
            // Create the document builder without a MetadataDb
            JsonDocumentBuilder<Mutable> documentBuilder = workspace.CreateBuilder<Mutable>(-1);
            ComplexValueBuilder cvb = ComplexValueBuilder.Create(documentBuilder, initialCapacity);
            var source = new Corvus.Cql2Benchmark.Current.Cql2Schema.IsNullPredicate.Source<TContext>(context, value);
            source.AddAsItem(ref cvb);
            Debug.Assert(cvb.MemberCount == 1);
            ((IMutableJsonDocument)documentBuilder).SetAndDispose(ref cvb);
            return documentBuilder;
        }

        /// <summary>
        /// Creates and initializes a mutable document from this instance.
        /// </summary>
        /// <param name="workspace">The JSON workspace.</param>
        /// <returns>An instance of a mutable document initialized with this instance.</returns>
        public JsonDocumentBuilder<Mutable> CreateBuilder(JsonWorkspace workspace)
        {
            return workspace.CreateBuilder<ComparisonPredicate, Mutable>(this);
        }
    }
}
